const _currentUserId=parseInt(document.body.dataset.userId || '0',10);let _changePwTargetId=null;let _changePwModal=null;let _usersCache=[];async function loadUsersList(){const tbody=document.getElementById('admin-users-table');tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted py-3">Загрузка…</td></tr>';const res=await window.Common.csrfFetch('/api/admin/users');if(!res.ok){tbody.innerHTML='<tr><td colspan="4" class="text-danger text-center py-3">Ошибка загрузки</td></tr>';return;}const users=await res.json();users.sort((a,b)=>{if(a.is_admin && !b.is_admin)return-1;if(!a.is_admin && b.is_admin)return 1;return a.id-b.id;});_usersCache=users;renderUsersTable(_usersCache);const sel=document.getElementById('bcUserCheckboxList');if(sel){const esc=window.Common.escapeHtml;sel.innerHTML=users.map(u=>{const avatarUrl=u.avatar ? `/static/avatars/${u.avatar}`:null;const avatarHtml=avatarUrl ? `<img src="${avatarUrl}" alt="${esc(u.username)}" style="width:24px;height:24px;border-radius:50%;object-fit:cover;margin-right:8px;">`:`<div style="width:24px;height:24px;border-radius:50%;background:var(--surface-3);color:var(--text-secondary);display:inline-flex;align-items:center;justify-content:center;font-size:10px;font-weight:bold;margin-right:8px;">${esc(u.username.substring(0,2).toUpperCase())}</div>`;return `<div class="form-check d-flex align-items-center mb-2"><input class="form-check-input bc-user-chk me-2" type="checkbox" value="${u.id}" id="bcUserChk${u.id}" style="margin-top:0;"><label class="form-check-label d-flex align-items-center mb-0 cursor-pointer" for="bcUserChk${u.id}">${avatarHtml}<span>${esc(u.username)}<small class="text-muted ms-1">(ID:${u.id})</small></span></label></div>`;}).join('');}}function renderUsersTable(usersToRender){const tbody=document.getElementById('admin-users-table');const esc=window.Common.escapeHtml;if(!usersToRender.length){tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted py-3">Не найдено</td></tr>';return;}tbody.innerHTML=usersToRender.map(u=>{const isSelf=u.id===_currentUserId;const isRoot=u.username==='root';const actions=isSelf ? '<span class="text-muted small">—</span>':`<div class="d-flex gap-1 flex-wrap">${!isRoot ? `<button class="btn btn-sm btn-outline-primary" data-action="changepw" data-uid="${u.id}" data-uname="${esc(u.username)}">Пароль</button>`:''}<button class="btn btn-sm btn-outline-danger" data-action="delete" data-uid="${u.id}" data-uname="${esc(u.username)}">Удалить</button></div>`;return `<tr><td class="text-muted small">${u.id}</td><td><b>${esc(u.username)}</b></td><td><span class="badge ${u.is_admin ? 'bg-danger':'bg-secondary'}">${u.is_admin ? 'Админ':'Юзер'}</span></td><td>${actions}</td></tr>`;}).join('');}document.getElementById('adminUserSearch')?.addEventListener('input',e=>{const q=e.target.value.toLowerCase().trim();if(!q){renderUsersTable(_usersCache);return;}const filtered=_usersCache.filter(u=>u.username.toLowerCase().includes(q)|| u.id.toString()===q);renderUsersTable(filtered);});document.getElementById('admin-users-table')?.addEventListener('click',e=>{const btn=e.target.closest('[data-action]');if(!btn)return;const uid=parseInt(btn.dataset.uid,10);const uname=btn.dataset.uname;if(btn.dataset.action==='delete')deleteUserTrigger(uid,uname);if(btn.dataset.action==='changepw')changePasswordTrigger(uid,uname);});function deleteUserTrigger(userId,name){window.Common.askConfirmation(`Удалить аккаунт «${name}» навсегда?`,async()=>{const res=await window.Common.csrfFetch(`/api/admin/delete_user/${userId}`,{method:'DELETE'});const data=await res.json();window.Common.showToast(data.message,!res.ok);loadUsersList();});}function changePasswordTrigger(userId,name){_changePwTargetId=userId;document.getElementById('changePwUsername').textContent=name;document.getElementById('changePwNew').value='';document.getElementById('changePwConfirm').value='';if(!_changePwModal)_changePwModal=new bootstrap.Modal(document.getElementById('changePwModal'));_changePwModal.show();}document.getElementById('changePwSubmitBtn').addEventListener('click',async()=>{const newPw=document.getElementById('changePwNew').value.trim();const confirm=document.getElementById('changePwConfirm').value.trim();if(!newPw || newPw.length<8){window.Common.showToast('Пароль должен содержать минимум 8 символов.',true);return;}if(newPw !==confirm){window.Common.showToast('Пароли не совпадают.',true);return;}const btn=document.getElementById('changePwSubmitBtn');btn.disabled=true;btn.textContent='Сохранение…';try{const res=await window.Common.csrfFetch(`/api/admin/change_password/${_changePwTargetId}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({new_password:newPw}),});const data=await res.json();if(res.ok){if(_changePwModal)_changePwModal.hide();window.Common.showToast(data.message);}else{window.Common.showToast(data.message,true);}}finally{btn.disabled=false;btn.textContent='Сохранить';}});document.getElementById('adminCreateUserForm').addEventListener('submit',async e=>{e.preventDefault();const btn=document.getElementById('createUserBtn');btn.disabled=true;btn.textContent='Создание…';try{const res=await window.Common.csrfFetch('/api/admin/add_user',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('newUsername').value,password:document.getElementById('newPassword').value,is_admin:document.getElementById('isAdminCheck').checked,})});const data=await res.json();if(res.ok){window.Common.showToast(data.message);e.target.reset();loadUsersList();}else{window.Common.showSystemMessage(data.message,true);}}finally{btn.disabled=false;btn.textContent='Создать';}});document.getElementById('refreshUsersBtn')?.addEventListener('click',loadUsersList);document.querySelectorAll('input[name="bcRecipients"]').forEach(r=>{r.addEventListener('change',()=>{document.getElementById('bcUserSelectWrap').style.display=document.getElementById('bcSelect').checked ? '':'none';});});document.getElementById('bcUserSearch')?.addEventListener('input',e=>{const q=e.target.value.toLowerCase().trim();const sel=document.getElementById('bcUserCheckboxList');if(!sel)return;const esc=window.Common.escapeHtml;sel.querySelectorAll('.form-check').forEach(div=>{const lbl=div.querySelector('label').textContent.toLowerCase();const chk=div.querySelector('input');if(lbl.includes(q)|| chk.value===q || !q){div.style.display='';}else{div.style.display='none';}});});document.getElementById('bcSendBtn')?.addEventListener('click',async()=>{const title=document.getElementById('bcTitle').value.trim();const body=document.getElementById('bcBody').value.trim();if(!title){window.Common.showToast('Введите заголовок',true);return;}const channels=[];if(document.getElementById('bcChSite').checked)channels.push('site');if(document.getElementById('bcChTg').checked)channels.push('telegram');if(!channels.length){window.Common.showToast('Выберите канал',true);return;}let recipients='all';if(document.getElementById('bcSelect').checked){recipients=Array.from(document.querySelectorAll('.bc-user-chk:checked')).map(o=>parseInt(o.value,10));if(!recipients.length){window.Common.showToast('Выберите хотя бы одного получателя',true);return;}}const btn=document.getElementById('bcSendBtn');btn.disabled=true;btn.textContent='Отправка…';try{const res=await window.Common.csrfFetch('/api/admin/broadcast',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title,body,recipients,channels}),});const data=await res.json();if(res.ok){window.Common.showToast(data.message);document.getElementById('bcTitle').value='';document.getElementById('bcBody').value='';}else{window.Common.showSystemMessage(data.message,true);}}finally{btn.disabled=false;btn.textContent='Отправить';}});loadUsersList();